const item = $input.first()?.json || {};
const body = item.body || {};
const data = item.chat_id ? item : (body.chat_id ? body : item);

const rawChatId = data.chat_id;
const rawText = data.text || data.ai_response || "";

// SEC04: Validar chat_id como numérico
const isValidChatId = /^\d+$/.test(String(rawChatId || ''));

// SEC05: Sanitizar text
const sanitizedText = String(rawText)
  .replace(/\\/g, '\\\\')
  .replace(/'/g, "''")
  .substring(0, 500);

// SEC04 Regex seguro: alfa-numerico, espacios, guiones, puntuacion
const isSafeText = /^[\w\sáéíóúÁÉÍÓÚñÑ\-.,!?()¿¡]+$/i.test(sanitizedText);
const isValidText = isSafeText && sanitizedText.trim().length > 2;

const isValid = isValidChatId && isValidText;

return [{ json: {
  isValid,
  chat_id: isValidChatId ? Number(rawChatId) : null,
  sessionId: String(rawChatId || ''),
  text: sanitizedText,
  _meta: {
    source: "NN_03-B_Pipeline_Agent",
    timestamp: new Date().toISOString(),
    workflow_id: "NN_03-B",
    version: "1.0.0"
  }
}}];

return [{ json: {
  success: false,
  error_code: "VALIDATION_ERROR",
  error_message: "Payload inválido para Pipeline Agent",
  data: null,
  _meta: {
    source: "NN_03-B_Pipeline_Agent",
    timestamp: new Date().toISOString(),
    workflow_id: "NN_03-B",
    version: "1.0.0"
  }
}}];

return [{ json: {
  success: false,
  error_code: "SECURITY_BLOCKED",
  error_message: "Se ha detectado contenido no permitido.",
  data: null,
  _meta: {
    source: "NN_03-B_Pipeline_Agent",
    timestamp: new Date().toISOString(),
    workflow_id: "NN_03-B",
    version: "1.0.0"
  }
}}];

let chatId = $('Extract & Validate (PRE)').item.json.chat_id;
const textOutput = $input.first()?.json?.message?.content || "Interacción general manejada por pipeline.";

return [{
  json: {
    success: true,
    error_code: null,
    error_message: null,
    data: {
      intent: "PIPELINE_RESPONSE",
      chat_id: chatId,
      ai_response: textOutput
    },
    _meta: {
      source: "NN_03-B_Pipeline_Agent",
      timestamp: new Date().toISOString(),
      workflow_id: "NN_03-B",
      version: "1.0.0"
    }
  }
}];

const content = $input.first()?.json?.message?.content || '{}';
let params = {};
try {
  const clean = content.replace(/```json/g, '').replace(/```/g, '');
  params = JSON.parse(clean);
} catch(e) {}

// Add chat_id automatically
params.chat_id = $('Extract & Validate (PRE)').item.json.chat_id;

return [{ json: params }];

